const body = $input.first().json.body || $input.first().json;
const transcript = body.transcript || '';
const callType = body.call_type || 'demo';

if (!transcript) {
  throw new Error('No transcript provided in request body');
}

// Call Gemini API using n8n HTTP helper
const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent',
  qs: {
    key: $env.GEMINI_API_KEY
  },
  headers: {
    'Content-Type': 'application/json'
  },
  body: {
    contents: [{
      parts: [{
        text: `You are a configuration assistant for Clara Answers.
Extract ONLY explicitly stated facts. Never invent missing info.
Return ONLY valid JSON. No markdown. No explanation.

Use this structure:
{
  "company_name": null,
  "business_hours": {"days": null, "start": null, "end": null, "timezone": null},
  "office_address": null,
  "services_supported": [],
  "emergency_definition": [],
  "emergency_routing_rules": {"primary_contact": null, "phone_number": null, "fallback": null},
  "non_emergency_routing_rules": {"action": null, "details": null},
  "call_transfer_rules": {"timeout_seconds": null, "fail_message": null},
  "special_clients": [],
  "pricing": {"service_call_fee": null, "hourly_rate": null, "mention_to_caller": null},
  "notification_preferences": {"email": null, "phone": null},
  "integration_constraints": [],
  "after_hours_flow_summary": null,
  "office_hours_flow_summary": null,
  "questions_or_unknowns": [],
  "notes": null
}

TRANSCRIPT:
${transcript}`
      }]
    }]
  },
  json: true
});

// Extract Gemini response
let raw = response.candidates?.[0]?.content?.parts?.[0]?.text?.trim();

if (!raw) {
  throw new Error('Empty response from Gemini API');
}

// Clean possible markdown wrapping
raw = raw.replace(/^```json\s*/, '').replace(/\s*```$/, '');

let memo;
try {
  memo = JSON.parse(raw);
} catch (err) {
  throw new Error('Failed to parse Gemini JSON output: ' + raw);
}

// Generate account_id
const slug = (memo.company_name || 'unknown')
  .toLowerCase()
  .replace(/[^a-z0-9]/g, '-')
  .slice(0, 24);

memo.account_id = slug + '-' + Date.now().toString(16).slice(-4);

memo._meta = {
  extracted_at: new Date().toISOString(),
  call_type: callType,
  version: 'v1'
};

return [{
  json: {
    memo,
    transcript,
    call_type: callType
  }
}];

const { memo } = $input.first().json;

const company = memo.company_name || 'our company';
const bh = memo.business_hours || {};
const days = bh.days || 'Monday to Friday';
const start = bh.start || '9:00 AM';
const end = bh.end || '5:00 PM';
const tz = bh.timezone || 'local time';
const routing = memo.emergency_routing_rules || {};
const phone = routing.phone_number || '[ON_CALL_NUMBER]';
const contact = routing.primary_contact || 'on-call team';
const timeout = (memo.call_transfer_rules || {}).timeout_seconds || 60;
const pricing = memo.pricing || {};

let pricingSection = '';
if (pricing.service_call_fee) {
  pricingSection = `
# PRICING (only mention if caller asks)
- Service call fee: ${pricing.service_call_fee}
- Hourly rate: ${pricing.hourly_rate}
- Do NOT mention on every call.`;
}

const systemPrompt = `# IDENTITY
You are Clara, AI voice assistant for ${company}.
Never say you are an AI unless asked.
Keep responses short — this is a phone call.

# BUSINESS HOURS
${days}, ${start} to ${end} ${tz}
${pricingSection}

---

# BUSINESS HOURS FLOW
Step 1 - Greeting: "Thank you for calling ${company}, this is Clara. How can I help?"
Step 2 - Understand purpose: emergency, service request, or inquiry?
Step 3 - Collect name and phone number. Repeat number back to confirm.
Step 4 - Transfer to ${contact} at ${phone}. Wait ${timeout} seconds.
Step 5 - If transfer fails: "I couldn't reach someone right now. Your info is noted and someone will call you back shortly."
Step 6 - "Is there anything else?" → "Thank you for calling ${company}. Have a great day!"

---

# AFTER HOURS FLOW
Step 1 - "Thank you for calling ${company}. Office is closed. This is Clara, how can I help?"
Step 2 - Determine if emergency or non-emergency.
Step 3a - IF EMERGENCY: collect name, phone, address → transfer to ${phone}
         If fails: "Your call is flagged urgent. Someone calls you back very shortly."
Step 3b - IF NOT EMERGENCY: collect details → "We will follow up next business day."
Step 4 - "Is there anything else?" → "Thank you. Have a good night!"

---

# RULES
- Never ask more than 2 questions at once
- Never mention tools, functions or systems
- Always repeat phone numbers back to confirm
- Be warm and calm always`;

const spec = {
  agent_name: `Clara - ${company}`,
  version: memo._meta?.version || 'v1',
  voice_style: {
    tone: 'warm, professional, calm',
    pace: 'natural, not rushed'
  },
  system_prompt: systemPrompt,
  key_variables: {
    company_name: company,
    timezone: bh.timezone,
    business_days: bh.days,
    emergency_phone: phone,
    transfer_timeout_seconds: timeout
  },
  call_transfer_protocol: {
    method: 'warm_transfer',
    timeout_seconds: timeout,
    announcement: 'Please hold while I connect you.'
  },
  fallback_protocol: {
    trigger: 'Transfer fails',
    message: "I'm sorry I couldn't reach someone. Your info is recorded and someone will follow up soon."
  },
  questions_or_unknowns: memo.questions_or_unknowns || [],
  _meta: {
    generated_at: new Date().toISOString(),
    account_id: memo.account_id
  }
};

return [{ json: { memo, spec } }];

